const items = $input.all();
const filename = items[0].json.name;
const mimeType = items[0].json.mimeType || '';
const fileSizeBytes = items[0].json.size || 0;
const fileSizeMB = fileSizeBytes / (1024 * 1024);

const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png', 'image/tiff', 'image/webp'];

if (!allowedTypes.includes(mimeType)) {
  throw new Error(`Invalid file type: ${mimeType}. Allowed: PDF, JPEG, PNG, TIFF, WebP. File: ${filename}`);
}

if (fileSizeMB < 0.1) {
  throw new Error(`File too small: ${(fileSizeMB * 1024).toFixed(0)}KB. Minimum: 100KB. File: ${filename}`);
}

if (fileSizeMB > 25) {
  throw new Error(`File too large: ${fileSizeMB.toFixed(1)}MB. Maximum: 25MB. File: ${filename}`);
}

const isbnRaw = filename.split('_')[0];

if (!/^\d{10}(\d{3})?$/.test(isbnRaw)) {
  throw new Error(`Invalid ISBN format: ${isbnRaw}. Expected: 10 or 13 digits. Example: 9781234567890_text.pdf`);
}

const fileType = filename.split('.').pop().toLowerCase();

return [{
  json: {
    isbn: isbnRaw,
    fileType: fileType,
    fileName: filename,
    fileId: items[0].json.id,
    webViewLink: items[0].json.webViewLink || items[0].json.webContentLink || '',
    mimeType: mimeType,
    fileSizeMB: parseFloat(fileSizeMB.toFixed(2)),
    validation_status: 'PASSED',
    validation_timestamp: new Date().toISOString()
  }
}];

const items = $input.all();
const rawResponse = items[0].json.content || '';
let cleanResponse = rawResponse;
if (cleanResponse.includes('```json')) {
  cleanResponse = cleanResponse.replace(/```json/g, '').replace(/```/g, '');
}
if (cleanResponse.includes('```')) {
  cleanResponse = cleanResponse.replace(/```/g, '');
}
cleanResponse = cleanResponse.trim();

let analysis;
try {
  analysis = JSON.parse(cleanResponse);
} catch (e) {
  analysis = {
    status: 'REVIEW_NEEDED',
    confidence_score: 0,
    badge_overlap: { detected: false, details: 'Parse error' },
    margin_violations: { detected: false, details: '' },
    text_alignment: { issues_detected: false, details: '' },
    image_quality: { score: 'unknown', details: '' },
    author_name: { text: 'Unknown', position: 'Unknown', safe_from_badge_zone: false },
    correction_instructions: 'Manual review required',
    issue_summary: 'AI parsing error'
  };
}

const isbn = $('Extract ISBN & Validate').item.json.isbn;
const fileName = $('Extract ISBN & Validate').item.json.fileName;
const webViewLink = $('Extract ISBN & Validate').item.json.webViewLink;

const issueTypes = [];
if (analysis.badge_overlap && analysis.badge_overlap.detected) issueTypes.push('Badge Overlap');
if (analysis.margin_violations && analysis.margin_violations.detected) issueTypes.push('Margin Violation');
if (analysis.text_alignment && analysis.text_alignment.issues_detected) issueTypes.push('Alignment Issue');
if (analysis.image_quality && analysis.image_quality.score === 'poor') issueTypes.push('Low Resolution');

let severity = '';
if (analysis.badge_overlap && analysis.badge_overlap.detected) {
  severity = 'Critical';
} else if (issueTypes.length > 0) {
  severity = 'Minor';
}

return [{
  json: {
    isbn: isbn,
    fileName: fileName,
    webViewLink: webViewLink,
    status: analysis.status || 'REVIEW_NEEDED',
    confidence_score: analysis.confidence_score || 0,
    badge_overlap_detected: (analysis.badge_overlap && analysis.badge_overlap.detected) || false,
    badge_overlap_details: (analysis.badge_overlap && analysis.badge_overlap.details) || '',
    margin_violations_detected: (analysis.margin_violations && analysis.margin_violations.detected) || false,
    margin_details: (analysis.margin_violations && analysis.margin_violations.details) || '',
    alignment_issues: (analysis.text_alignment && analysis.text_alignment.issues_detected) || false,
    image_quality_score: (analysis.image_quality && analysis.image_quality.score) || 'unknown',
    author_name: (analysis.author_name && analysis.author_name.text) || 'Unknown',
    author_position: (analysis.author_name && analysis.author_name.position) || '',
    author_safe_from_badge: (analysis.author_name && analysis.author_name.safe_from_badge_zone) || false,
    issue_types: issueTypes.join(', ') || 'None',
    issue_count: issueTypes.length,
    severity: severity,
    correction_instructions: analysis.correction_instructions || '',
    issue_summary: analysis.issue_summary || '',
    ai_processing_timestamp: new Date().toISOString()
  }
}];

const lookupResult = $input.all()[0].json;
const records = lookupResult.records || [];
const parseData = $('Parse AI Response').item.json;

if (records.length === 0) {
  return [{
    json: {
      ...parseData,
      author_email: null,
      author_record_found: false,
      requires_support_escalation: true,
      escalation_reason: 'ISBN_NOT_IN_AIRTABLE',
      escalation_details: `ISBN ${parseData.isbn} not found in Airtable`
    }
  }];
}

const record = records[0];
const authorEmail = record.fields['Author email'];
const airtableAuthorName = record.fields['Author name'];
const currentRevision = parseInt(record.fields['Revision number'] || 0);
const lastSubmissionTime = record.fields['Detection timestamp'];

if (!authorEmail || authorEmail.trim() === '') {
  return [{
    json: {
      ...parseData,
      author_email: null,
      author_record_found: true,
      requires_support_escalation: true,
      escalation_reason: 'EMAIL_NOT_POPULATED',
      escalation_details: `Author email missing for ISBN ${parseData.isbn}`
    }
  }];
}

if (lastSubmissionTime) {
  const lastSubmissionDate = new Date(lastSubmissionTime);
  const currentTime = new Date();
  const timeDiffSeconds = (currentTime - lastSubmissionDate) / 1000;
  if (timeDiffSeconds < 300) {
    return [{
      json: {
        ...parseData,
        author_email: authorEmail,
        requires_support_escalation: true,
        escalation_reason: 'DUPLICATE_SUBMISSION',
        escalation_details: `Same ISBN uploaded less than 5 minutes ago`,
        skip_processing: true
      }
    }];
  }
}

const finalAuthorName = (airtableAuthorName && airtableAuthorName.trim()) ? airtableAuthorName : parseData.author_name;
const nextRevisionNumber = currentRevision + 1;

return [{
  json: {
    ...parseData,
    author_email: authorEmail.toLowerCase().trim(),
    author_name: finalAuthorName,
    author_record_found: true,
    next_revision_number: nextRevisionNumber,
    requires_support_escalation: false,
    escalation_reason: null,
    skip_processing: false
  }
}];
